   584→  <script src="/js/main.js"></script>
   585→  <script>
   586→    const TOKEN_KEY = 'rekrutai_token';
   587→    let wizardState = null;
   588→    let checklistData = null;
   589→    let documentsData = [];
   590→    let currentStep = 1;
   591→    let signatureCanvas = null;
   592→    let signatureCtx = null;
   593→    let isDrawing = false;
   594→    let hasSigned = false;
   595→
   596→    const STEPS = [
   597→      { num: 1, label: 'Personal Info' },
   598→      { num: 2, label: 'Emergency Contact' },
   599→      { num: 3, label: 'Direct Deposit' },
   600→      { num: 4, label: 'Review & Sign' },
   601→      { num: 5, label: 'Complete' }
   602→    ];
   603→
   604→    function getToken() {
   605→      return localStorage.getItem(TOKEN_KEY);
   606→    }
   607→
   608→    function getAuthHeaders() {
   609→      const token = getToken();
   610→      return token ? {
   611→        'Authorization': `Bearer ${token}`,
   612→        'Content-Type': 'application/json'
   613→      } : {};
   614→    }
   615→
   616→    // Initialize
   617→    document.addEventListener('DOMContentLoaded', async () => {
   618→      const token = getToken();
   619→      if (!token) {
   620→        window.location.href = '/login.html';
   621→        return;
   622→      }
   623→
   624→      // Load user info for sidebar
   625→      try {
   626→        const userRes = await fetch('/api/auth/me', { headers: { 'Authorization': `Bearer ${token}` } });
   627→        if (userRes.ok) {
   628→          const userData = await userRes.json();
   629→          document.getElementById('user-name').textContent = userData.name || 'User';
   630→          document.getElementById('user-avatar').textContent = (userData.name || 'U')[0].toUpperCase();
   631→          if (document.getElementById('dropdown-user-name')) {
   632→            document.getElementById('dropdown-user-name').textContent = userData.name || 'User';
   633→            document.getElementById('dropdown-user-email').textContent = userData.email || '';
   634→          }
   635→        }
   636→      } catch(e) { /* ignore */ }
   637→
   638→      // Setup user dropdown
   639→      const toggle = document.getElementById('user-menu-toggle');
   640→      const menu = document.getElementById('user-dropdown-menu');
   641→      if (toggle && menu) {
   642→        toggle.addEventListener('click', () => menu.classList.toggle('active'));
   643→        document.addEventListener('click', (e) => {
   644→          if (!toggle.contains(e.target) && !menu.contains(e.target)) menu.classList.remove('active');
   645→        });
   646→      }
   647→
   648→      const logoutBtn = document.getElementById('logout-btn');
   649→      if (logoutBtn) {
   650→        logoutBtn.addEventListener('click', () => {
   651→          localStorage.removeItem(TOKEN_KEY);
   652→          localStorage.removeItem('rekrutai_refresh');
   653→          window.location.href = '/login.html';
   654→        });
   655→      }
