  1253→    // ====== Signature Canvas ======
  1254→    function initSignatureCanvas() {
  1255→      const canvas = document.getElementById('signatureCanvas');
  1256→      if (!canvas) return;
  1257→
  1258→      signatureCanvas = canvas;
  1259→      signatureCtx = canvas.getContext('2d');
  1260→
  1261→      // Set canvas size
  1262→      const rect = canvas.parentElement.getBoundingClientRect();
  1263→      canvas.width = rect.width - 48;
  1264→      canvas.height = 150;
  1265→
  1266→      signatureCtx.strokeStyle = '#1a1a2e';
  1267→      signatureCtx.lineWidth = 2;
  1268→      signatureCtx.lineCap = 'round';
  1269→      signatureCtx.lineJoin = 'round';
  1270→
  1271→      canvas.addEventListener('mousedown', startDrawing);
  1272→      canvas.addEventListener('mousemove', draw);
  1273→      canvas.addEventListener('mouseup', stopDrawing);
  1274→      canvas.addEventListener('mouseleave', stopDrawing);
  1275→
  1276→      // Touch support
  1277→      canvas.addEventListener('touchstart', (e) => {
  1278→        e.preventDefault();
  1279→        const touch = e.touches[0];
  1280→        const rect = canvas.getBoundingClientRect();
  1281→        startDrawing({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1282→      });
  1283→      canvas.addEventListener('touchmove', (e) => {
  1284→        e.preventDefault();
  1285→        const touch = e.touches[0];
  1286→        const rect = canvas.getBoundingClientRect();
  1287→        draw({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1288→      });
  1289→      canvas.addEventListener('touchend', stopDrawing);
  1290→    }
  1291→
  1292→    function startDrawing(e) {
  1293→      isDrawing = true;
  1294→      signatureCtx.beginPath();
  1295→      signatureCtx.moveTo(e.offsetX, e.offsetY);
  1296→    }
  1297→
  1298→    function draw(e) {
  1299→      if (!isDrawing) return;
  1300→      signatureCtx.lineTo(e.offsetX, e.offsetY);
  1301→      signatureCtx.stroke();
  1302→      hasSigned = true;
  1303→      const btn = document.getElementById('signAllBtn');
  1304→      if (btn) btn.disabled = false;
  1305→    }
  1306→
  1307→    function stopDrawing() {
  1308→      isDrawing = false;
  1309→    }
  1310→
  1311→    function clearSignature() {
  1312→      if (!signatureCanvas || !signatureCtx) return;
  1313→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1314→      hasSigned = false;
  1315→      const btn = document.getElementById('signAllBtn');
  1316→      if (btn) btn.disabled = true;
  1317→    }
  1318→
  1319→    function typeSignature() {
  1320→      const name = prompt('Type your full legal name as your signature:');
  1321→      if (!name || !name.trim()) return;
  1322→
  1323→      if (!signatureCanvas || !signatureCtx) return;
  1324→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1325→      signatureCtx.font = 'italic 32px "Times New Roman", serif';
  1326→      signatureCtx.fillStyle = '#1a1a2e';
  1327→      signatureCtx.textAlign = 'center';
  1328→      signatureCtx.fillText(name.trim(), signatureCanvas.width / 2, 90);
  1329→      hasSigned = true;
  1330→      const btn = document.getElementById('signAllBtn');
  1331→      if (btn) btn.disabled = false;
  1332→    }
