  1484→    function escapeHtml(text) {
  1485→      if (!text) return '';
  1486→      const map = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' };
  1487→      return String(text).replace(/[&<>"']/g, m => map[m]);
