   189→  <script>
   190→    document.addEventListener('DOMContentLoaded', async () => {
   191→      const user = await checkAuth();
   192→      if (!user) {
   193→        window.location.href = '/login.html';
   194→        return;
   195→      }
   196→      // Allow access if user has company_id OR is a recruiter
   197→      if (!user.company_id && user.role !== 'recruiter') {
   198→        window.location.href = '/dashboard.html';
   199→        return;
   200→      }
   201→
   202→      const name = user.name || user.email.split('@')[0];
   203→      document.getElementById('user-name').textContent = name;
   204→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   205→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   206→
   207→      loadTrustScore();
   208→    });
   209→
   210→    async function loadTrustScore() {
   211→      try {
   212→        const data = await apiCall('/trustscore/breakdown');
   213→        if (!data) return;
   214→
   215→        const { current, breakdown, recommendations, history } = data;
   216→
   217→        // Update main score
   218→        document.getElementById('main-score').textContent = current.total_score;
   219→        document.getElementById('tier-badge').textContent = current.tier_label;
   220→        document.getElementById('tier-badge').style.background = current.tier_color;
   221→
   222→        // Animate score ring
   223→        const ring = document.getElementById('score-ring');
   224→        const percentage = current.total_score / 1000;
   225→        const offset = 565.5 * (1 - percentage);
   226→        setTimeout(() => {
   227→          ring.style.strokeDashoffset = offset;
   228→        }, 100);
   229→
   230→        // Tier description
   231→        const descriptions = {
   232→          exceptional: 'Top-tier employer! Candidates trust your company highly.',
   233→          excellent: 'Excellent reputation. Candidates view you favorably.',
   234→          trusted: 'Trusted employer with good hiring practices.',
   235→          good: 'Good standing. Room for improvement.',
   236→          building: 'Building trust. Follow recommendations below.',
   237→          new: 'New employer. Complete actions to build credibility.'
   238→        };
   239→        document.getElementById('tier-description').textContent = descriptions[current.tier] || descriptions.new;
   240→
   241→        // Render breakdown
   242→        renderBreakdown(breakdown);
   243→
   244→        // Render recommendations
   245→        renderRecommendations(recommendations);
   246→
   247→        // Render history
   248→        renderHistory(history);
   249→
   250→      } catch (err) {
   251→        console.error('Failed to load TrustScore:', err);
   252→      }
   253→    }
   254→
   255→    function renderBreakdown(breakdown) {
   256→      const container = document.getElementById('breakdown-list');
   257→      container.innerHTML = breakdown.map(item => {
   258→        const percentage = (item.score / item.max) * 100;
   259→        return `
   260→          <div class="breakdown-item">
   261→            <div class="breakdown-header">
   262→              <span class="breakdown-label">${item.label}</span>
   263→              <span class="breakdown-score">${item.score}/${item.max}</span>
   264→            </div>
   265→            <div class="breakdown-bar">
   266→              <div class="breakdown-fill" style="width: ${percentage}%"></div>
   267→            </div>
   268→            <span class="breakdown-desc">${item.description}</span>
   269→          </div>
   270→        `;
   271→      }).join('');
   272→    }
   273→
   274→    function renderRecommendations(recommendations) {
   275→      const container = document.getElementById('recommendations');
   276→
   277→      if (!recommendations || recommendations.length === 0) {
   278→        container.innerHTML = `
   279→          <div class="empty-state">
   280→            <p>Great job! No immediate recommendations.</p>
   281→          </div>
   282→        `;
   283→        return;
   284→      }
   285→
   286→      container.innerHTML = recommendations.map(rec => `
   287→        <div class="recommendation-card priority-${rec.priority}">
   288→          <div class="rec-priority">${rec.priority}</div>
   289→          <h4>${rec.title}</h4>
   290→          <p>${rec.description}</p>
   291→          <div class="rec-gain">+${rec.potential_gain} potential points</div>
   292→        </div>
   293→      `).join('');
   294→    }
   295→
   296→    function renderHistory(history) {
   297→      const container = document.getElementById('history-list');
   298→
   299→      if (!history || history.length === 0) {
   300→        container.innerHTML = `
   301→          <div class="empty-state">
   302→            <p>No score changes yet.</p>
   303→          </div>
   304→        `;
   305→        return;
   306→      }
   307→
   308→      container.innerHTML = history.map(h => `
   309→        <div class="history-item">
   310→          <div class="history-change ${h.change_amount >= 0 ? 'positive' : 'negative'}">
   311→            ${h.change_amount >= 0 ? '+' : ''}${h.change_amount}
   312→          </div>
   313→          <div class="history-info">
   314→            <span class="history-reason">${h.change_reason}</span>
   315→            <span class="history-date">${new Date(h.created_at).toLocaleDateString()}</span>
   316→          </div>
   317→          <div class="history-scores">
   318→            <span>${h.previous_score}</span>
   319→            <span class="arrow">→</span>
   320→            <span>${h.new_score}</span>
   321→          </div>
   322→        </div>
   323→      `).join('');
   324→    }
