   367→  <script>
   368→    let allSkills = [];
   369→    let currentFilter = 'all';
   370→
   371→    // Load available assessments from catalog
   372→    async function loadAssessments() {
   373→      try {
   374→        const response = await fetch('/api/assessments/available', {
   375→          headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` }
   376→        });
   377→
   378→        if (!response.ok) throw new Error('Failed to load assessments');
   379→
   380→        const data = await response.json();
   381→        allSkills = data.skills || [];
   382→        renderSkills(allSkills);
   383→      } catch (error) {
   384→        console.error('Error loading assessments:', error);
   385→        document.getElementById('assessments-grid').innerHTML = `
   386→          <div class="empty-state">
   387→            <div class="empty-state-icon">❌</div>
   388→            <p>Failed to load skill catalog. Please refresh.</p>
   389→          </div>
   390→        `;
   391→      }
   392→    }
   393→
   394→    // Filter skills by category
   395→    function filterSkills(category) {
   396→      currentFilter = category;
   397→      document.querySelectorAll('.filter-tab').forEach(tab => tab.classList.remove('active'));
   398→      event.target.classList.add('active');
   399→
   400→      if (category === 'all') {
   401→        renderSkills(allSkills);
   402→      } else {
   403→        renderSkills(allSkills.filter(s => s.category === category));
   404→      }
   405→    }
   406→
   407→    // Render skill cards
   408→    function renderSkills(skills) {
   409→      const grid = document.getElementById('assessments-grid');
   410→
   411→      if (skills.length === 0) {
   412→        grid.innerHTML = `
   413→          <div class="empty-state">
   414→            <div class="empty-state-icon">📝</div>
   415→            <p>No skills in this category.</p>
   416→          </div>
   417→        `;
   418→        return;
   419→      }
   420→
   421→      grid.innerHTML = skills.map(skill => `
   422→        <div class="assessment-card ${skill.is_verified ? 'verified' : ''}" onclick="startAssessment('${skill.catalog_name.replace(/'/g, "\\'")}', '${skill.category}')">
   423→          <div class="assessment-header">
   424→            <div class="skill-icon">${skill.icon}</div>
   425→            ${skill.is_verified ? '<span class="verified-badge">✓ Verified</span>' : ''}
   426→          </div>
   427→
   428→          <div class="assessment-title">${skill.catalog_name}</div>
   429→          <div class="assessment-description">${skill.description}</div>
   430→
   431→          <div class="assessment-meta">
   432→            <span class="meta-tag">${skill.category.replace('_', ' ')}</span>
   433→            <span class="meta-tag">🎯 Adaptive</span>
   434→            <span class="meta-tag">⏱️ 10 questions</span>
   435→          </div>
   436→
   437→          <div class="assessment-stats">
   438→            <div class="stat-item">
   439→              <span class="stat-value">${skill.assessment_count || 0}</span>
   440→              <span class="stat-label">Attempts</span>
   441→            </div>
   442→            <div class="stat-item">
   443→              <span class="stat-value">${skill.best_score != null ? skill.best_score : '—'}</span>
   444→              <span class="stat-label">Best Score</span>
   445→            </div>
   446→            <div class="stat-item">
   447→              <span class="stat-value">${skill.verified_score != null ? skill.verified_score + '%' : '—'}</span>
   448→              <span class="stat-label">Verified</span>
   449→            </div>
   450→          </div>
   451→
   452→          <div class="assessment-actions">
   453→            <button class="btn ${skill.is_verified ? 'btn-ghost' : 'btn-primary'}" style="flex: 1;">
   454→              ${skill.is_verified ? '🔄 Retake Test' : '▶️ Start Test'}
   455→            </button>
   456→          </div>
   457→        </div>
   458→      `).join('');
   459→    }
   460→
   461→    // Load past results
   462→    async function loadResults() {
   463→      try {
   464→        const response = await fetch('/api/assessments/results', {
   465→          headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` }
   466→        });
   467→
   468→        if (!response.ok) throw new Error('Failed to load results');
   469→
   470→        const data = await response.json();
   471→        const list = document.getElementById('results-list');
   472→
   473→        if (!data.results || data.results.length === 0) {
   474→          list.innerHTML = `
   475→            <div class="empty-state">
   476→              <div class="empty-state-icon">📊</div>
   477→              <p>No completed assessments yet. Take your first test above!</p>
   478→            </div>
   479→          `;
   480→          return;
   481→        }
   482→
   483→        list.innerHTML = data.results.map(result => {
   484→          const date = new Date(result.completed_at);
   485→          const hasWarnings = (result.tab_switches || 0) > 0 || (result.copy_paste_attempts || 0) > 0;
   486→
   487→          return `
   488→            <div class="result-item">
   489→              <div class="result-score">${result.score}</div>
   490→              <div class="result-info">
   491→                <div class="result-title">${result.skill_name || result.title || 'Assessment'}</div>
   492→                <div class="result-meta">
   493→                  Completed ${date.toLocaleDateString()} • Max Difficulty: ${result.max_difficulty_reached || 2}/5
   494→                </div>
   495→                <div class="result-badges">
   496→                  <span class="badge ${result.passed ? 'passed' : ''}">${result.passed ? '✓ Passed' : '✗ Not Passed'}</span>
   497→                  ${hasWarnings ? '<span class="badge warning">⚠️ Behavioral flags</span>' : '<span class="badge">✓ Clean attempt</span>'}
   498→                </div>
   499→              </div>
   500→              <a href="/assessment-results.html?session=${result.session_id}" class="btn btn-ghost">View Details</a>
   501→            </div>
   502→          `;
   503→        }).join('');
   504→      } catch (error) {
   505→        console.error('Error loading results:', error);
   506→      }
   507→    }
   508→
   509→    // Start assessment - now passes skill name + category
   510→    function startAssessment(skillName, category) {
   511→      localStorage.setItem('assessment_skill_name', skillName);
   512→      localStorage.setItem('assessment_skill_category', category);
   513→      window.location.href = '/assessment-take.html';
   514→    }
   515→
   516→    // Initialize
   517→    document.addEventListener('DOMContentLoaded', async () => {
   518→      await checkAuth();
   519→      setupUserMenu();
   520→      loadAssessments();
   521→      loadResults();
   522→    });
   523→  </script>
